import{_ as t,o as s,c as a,a5 as r}from"./chunks/framework.UipYbTJA.js";const m=JSON.parse('{"title":"Access the observability stack","description":"","frontmatter":{"title":"Access the observability stack","personas":["platform-owner"]},"headers":[],"relativePath":"how-to-guides/access-observability.md","filePath":"how-to-guides/access-observability.md"}'),i={name:"how-to-guides/access-observability.md"};function o(c,e,l,n,h,p){return s(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="access-the-observability-stack" tabindex="-1">Access the observability stack <a class="header-anchor" href="#access-the-observability-stack" aria-label="Permalink to &quot;Access the observability stack&quot;">​</a></h1><p>The observability stack includes a bundled Prometheus instance for metrics during local development and testing. This guide shows how to access it.</p><div class="tip custom-block"><p class="custom-block-title">Other Telemetry Data</p><p>Platform Mesh also collects traces and can forward metrics to external backends. Accessing this data depends on your chosen storage backend – see <a href="/pr-preview/pr-234/concepts/observability.html">Observability concepts</a> for the full architecture and integration patterns.</p></div><div class="warning custom-block"><p class="custom-block-title">Local setup only</p><p>The bundled Prometheus is intended for development and testing. For production deployments, configure the OpenTelemetry Collector to forward metrics and traces to your existing infrastructure.</p></div><h2 id="forward-the-prometheus-service" tabindex="-1">Forward the Prometheus service <a class="header-anchor" href="#forward-the-prometheus-service" aria-label="Permalink to &quot;Forward the Prometheus service&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">kubectl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> port-forward</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> observability</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> svc/observability-prometheus-server</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 9090:80</span></span></code></pre></div><h2 id="open-the-prometheus-ui" tabindex="-1">Open the Prometheus UI <a class="header-anchor" href="#open-the-prometheus-ui" aria-label="Permalink to &quot;Open the Prometheus UI&quot;">​</a></h2><p>Open:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:9090</span></span></code></pre></div><p>The Prometheus UI lets you explore metrics, run queries, and verify that Platform Mesh components are being scraped correctly.</p><h2 id="explore-platform-mesh-metrics" tabindex="-1">Explore Platform Mesh metrics <a class="header-anchor" href="#explore-platform-mesh-metrics" aria-label="Permalink to &quot;Explore Platform Mesh metrics&quot;">​</a></h2><p>Use the Prometheus expression browser to query metrics. Platform Mesh components expose controller-runtime metrics (for operators) and component-specific metrics.</p><p>To verify metrics are being collected, try querying for metrics from Platform Mesh components. For example, search for metrics with prefixes like <code>controller_runtime_</code> or <code>openfga_</code>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-234/reference/components/observability.html">Observability reference</a></li><li><a href="/pr-preview/pr-234/concepts/observability.html">Observability concepts</a></li><li><a href="/pr-preview/pr-234/how-to-guides/access-openfga.html">Access OpenFGA</a></li></ul>',15)])])}const b=t(i,[["render",o]]);export{m as __pageData,b as default};
